import React, { useState } from 'react';
import { catalogoInicial } from './data/cuentas';
import './styles/global.css';

function App() {
  const [bal, setBal] = useState(catalogoInicial);
  const [f, setF] = useState("13 de marzo de 2026");
  const [input, setInput] = useState({ cuenta: 'bancos', monto: '', tipo: 'cargo' });

  const ver = (dia) => {
    let n = JSON.parse(JSON.stringify(catalogoInicial));
    if (dia === '28') {
      setF("28 de enero de 2026");
      n.activo.bancos = 1520; n.activo.inventarios = 10000;
    } else if (dia === '30') {
      setF("30 de enero de 2026");
      n.activo.bancos = 1520; n.activo.rentas = 5000; n.pasivo.acreedores = 16240;
    } else if (dia === '04') {
      setF("4 de febrero de 2026");
      n.pasivo.anticipoClientes = 4000; n.capital = 1371000;
    } else {
      setF("13 de marzo de 2026");
    }
    setBal(n);
  };

  const procesarEntrada = (e) => {
    e.preventDefault();
    let n = JSON.parse(JSON.stringify(bal));
    const valor = Number(input.monto);
    if (input.tipo === 'cargo') {
      if (n.activo[input.cuenta] !== undefined) n.activo[input.cuenta] += valor;
      else if (n.pasivo[input.cuenta] !== undefined) n.pasivo[input.cuenta] -= valor;
    } else {
      if (n.activo[input.cuenta] !== undefined) n.activo[input.cuenta] -= valor;
      else if (n.pasivo[input.cuenta] !== undefined) n.pasivo[input.cuenta] += valor;
    }
    setBal(n); setInput({ ...input, monto: '' });
  };

  const tA = Object.values(bal.activo).reduce((a, b) => a + (Number(b) || 0), 0);
  const tPC = Object.values(bal.pasivo).reduce((a, b) => a + (Number(b) || 0), 0) + (Number(bal.capital) || 0) + (Number(bal.utilidad) || 0);

  return (
    <div className="app-layout">
      <aside className="sidebar no-print">
        <h2 className="brand">FINTECH MAYI</h2>
        <div className="menu-group">
          <p className="entry-title">HISTORIAL</p>
          <button className="btn-nav" onClick={() => ver('23')}>23 Ene - Apertura</button>
          <button className="btn-nav" onClick={() => ver('28')}>28 Ene - Compra</button>
          <button className="btn-nav" onClick={() => ver('30')}>30 Ene - Ajustes</button>
          <button className="btn-nav" onClick={() => ver('04')}>04 Feb - Anticipo</button>
        </div>
        <form className="data-entry" onSubmit={procesarEntrada}>
          <p className="entry-title">SIMULADOR</p>
          <select value={input.cuenta} onChange={(e) => setInput({...input, cuenta: e.target.value})}>
            <option value="bancos">Bancos</option>
            <option value="inventarios">Inventarios</option>
            <option value="acreedores">Acreedores</option>
          </select>
          <input type="number" placeholder="Monto" value={input.monto} onChange={(e) => setInput({...input, monto: e.target.value})} />
          <button type="submit" className="btn-save">Registrar</button>
        </form>
        <button className="btn-pdf" onClick={() => window.print()}>GENERAR PDF</button>
      </aside>

      <main className="main-content">
        <div className="paper">
          <header className="header-report">
            <h1>COCINA ECONÓMICA MAYI</h1>
            <div className="badge-fintech">Estado de Situación Financiera</div>
            <p>Al {f}</p>
          </header>
          <div className="grid-balance">
            <div className="col">
              <h4>ACTIVOS</h4>
              {Object.entries(bal.activo).map(([k, v]) => (
                v > 0 && <div className="r" key={k}><span>{k.toUpperCase()}</span><span>${v.toLocaleString()}</span></div>
              ))}
              <div className="total-bar"><span>TOTAL ACTIVO</span><span>${tA.toLocaleString()}</span></div>
            </div>
            <div className="col">
              <h4>PASIVO + CAPITAL</h4>
              {Object.entries(bal.pasivo).map(([k, v]) => (
                <div className="r" key={k}><span>{k.toUpperCase()}</span><span>${v.toLocaleString()}</span></div>
              ))}
              <div className="r"><span>CAPITAL SOCIAL</span><span>${bal.capital.toLocaleString()}</span></div>
              <div className="r highlight"><span>UTILIDAD NETA</span><span>${bal.utilidad.toLocaleString()}</span></div>
              <div className="total-bar"><span>TOTAL P + C</span><span>${tPC.toLocaleString()}</span></div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
export default App;
